/** Manifest — describes the params surface of stdStemLabLabResultOrbital. */
export const StdStemLabLabResultOrbitalManifest = {
  organism: 'std-stem-lab',
  orbitalName: 'LabResultOrbital',
  paramFields: [
    { name: 'fields', type: 'EntityField[]', description: 'Extra fields appended to the canonical entity.' },
    { name: 'pagePath', type: 'string', description: 'URL override for the orbital first page.' },
    { name: 'persistence', type: "'persistent' | 'runtime' | 'singleton' | 'instance' | 'local'", description: 'Override the canonical entity persistence mode.' },
    { name: 'entityName', type: 'string', description: 'Rename the canonical entity. PascalCase singular, ≤32 chars. Threads through every trait\'s linkedEntity binding; compiler rewrites @Entity.x refs.' },
    { name: 'collection', type: 'string', description: 'Override derived collection key. Defaults to plural(entityName).toLowerCase().' },
    { name: 'traitOverrides', type: "Partial<Record<TraitName, { config?, linkedEntity?, events?, name?, emitsScope?, listens? }>>", description: 'Per-imported-trait overrides — mirrors .lolo\'s native trait-composition surface 1:1. effects is excluded (atom-owned; use listens via a sibling trait).' },
  ] as const,
  traitNames: [
  ] as const,
  inlineTraitNames: [
    'LabResultDisplay',
  ] as const,
};

/** Typed guard — runtime validates StdStemLabLabResultOrbitalParams keys. */
export function isStdStemLabLabResultOrbitalParams(p: object): p is StdStemLabLabResultOrbitalParams {
  type _OverrideRecord = NonNullable<StdStemLabLabResultOrbitalParams['traitOverrides']>;
  const obj = p as { traitOverrides?: _OverrideRecord };
  if (obj.traitOverrides !== undefined) {
    if (typeof obj.traitOverrides !== "object" || obj.traitOverrides === null) return false;
    const allowed: readonly string[] = [
      ...StdStemLabLabResultOrbitalManifest.traitNames,
      ...StdStemLabLabResultOrbitalManifest.inlineTraitNames,
    ];
    for (const k of Object.keys(obj.traitOverrides)) {
      if (!allowed.includes(k)) return false;
    }
  }
  return true;
}

/**
 * Bundled params for std-stem-lab — one optional entry per orbital.
 * Each entry maps to its per-orbital factory above.
 */
export interface StdStemLabParams {
  Experiment?: StdStemLabExperimentOrbitalParams;
  Classification?: StdStemLabClassificationOrbitalParams;
  LabResult?: StdStemLabLabResultOrbitalParams;
}

/** Whole-organism descriptor (3 orbitals). Composes per-orbital factories. */
export function stdStemLab(params: StdStemLabParams = {}): OrbitalDefinition[] {
  return [
    stdStemLabExperimentOrbital(params.Experiment ?? {}),
    stdStemLabClassificationOrbital(params.Classification ?? {}),
    stdStemLabLabResultOrbital(params.LabResult ?? {}),
  ];
}
